from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    for subject, triples in subject_map.items():
        if sentence:
            sentence += " which "
        sentence += f"{subject} "

        # Track predicates to avoid duplicates
        processed_predicates = set()

        for i, (predicate, obj) in enumerate(triples):
            # Skip if already processed (avoid duplicates)
            if predicate in processed_predicates:
                continue
            processed_predicates.add(predicate)

            if predicate == "cityServed":
                sentence += f"serves the city of {obj}"
            elif predicate == "mayor":
                sentence += f"has a mayor named {obj}"
